import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{r as c,o as a,c as r,a as e,b as o,d,e as n}from"./app-be253e4c.js";const t="/JavaScriptCollection/assets/vim-53b51753.gif",h={},u=n('<h1 id="linux-vi-vim" tabindex="-1"><a class="header-anchor" href="#linux-vi-vim" aria-hidden="true">#</a> Linux vi/vim</h1><figure><img src="'+t+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>命令模式（Command mode）：VIM 的默认模式，可以用于移动游标查看内容；</li><li>编辑模式（Insert mode）：按下 &quot;i&quot; 等按键之后进入，可以对文本进行编辑；</li><li>指令列模式（Bottom-line mode）：按下 &quot;:&quot; 按键之后进入，用于保存退出等操作。</li></ul><p>在指令列模式下，离开或者保存文件常用命令：</p><ul><li><code>:w</code> 写入磁盘</li><li><code>:w!</code> 当文件为只读时，强制写入磁盘。到底能不能写入，与用户对该文件的权限有关</li><li><code>:q</code> 离开</li><li><code>:q!</code> 强制离开不保存</li><li><code>:wq</code> 写入磁盘后离开</li><li><code>:wq!</code> 强制写入磁盘后离开</li></ul><h2 id="命令模式" tabindex="-1"><a class="header-anchor" href="#命令模式" aria-hidden="true">#</a> 命令模式</h2><p>用户刚刚启动 vi/vim，便进入了命令模式。</p><p>此状态下敲击键盘动作会被Vim识别为命令，而非输入字符。比如我们此时按下<code>i</code>，并不会输入一个字符，i被当作了一个命令。</p><p>以下是常用的几个命令：</p><ul><li><code>i</code> 切换到输入模式，以输入字符。</li><li><code>x</code> 删除当前光标所在处的字符。</li><li><code>:</code> 切换到底线命令模式，以在最底一行输入命令。 若想要编辑文本：启动Vim，进入了命令模式，按下i，切换到输入模式。</li></ul><p>命令模式只有一些最基本的命令，因此仍要依靠底线命令模式输入更多命令</p><h2 id="输入模式" tabindex="-1"><a class="header-anchor" href="#输入模式" aria-hidden="true">#</a> 输入模式</h2><p>在命令模式下按下i就进入了输入模式。</p><p>在输入模式中，可以使用以下按键：</p><ul><li>字符按键以及<code>Shift</code>组合，输入字符</li><li><code>ENTER</code> 回车键，换行</li><li><code>BACK SPACE</code> 退格键，删除光标前一个字符</li><li><code>DEL</code> 删除键，删除光标后一个字符</li><li><code>HOME/END</code> 移动光标到行首/行尾</li><li><code>Page Up/Page Down</code> 上/下翻页</li><li><code>Insert</code> 切换光标为输入/替换模式，光标将变成竖线/下划线</li><li><code>ESC</code> 退出输入模式，切换到命令模式</li></ul><h2 id="指令列模式" tabindex="-1"><a class="header-anchor" href="#指令列模式" aria-hidden="true">#</a> 指令列模式</h2><p>在输入模式模式下按下<code>:</code>（英文冒号）就能进入。</p><p>指令列模式可以输入单个或多个字符的命令，可用的命令非常多。</p><p>在指令列模式中，基本的命令有（已经省略了冒号）：</p><ul><li><code>q</code> 退出程序</li><li><code>w</code> 保存文件</li></ul><p>按<code>ESC</code>键可随时退出指令列模式。</p><h2 id="常用命令操作" tabindex="-1"><a class="header-anchor" href="#常用命令操作" aria-hidden="true">#</a> 常用命令操作</h2><h3 id="退出" tabindex="-1"><a class="header-anchor" href="#退出" aria-hidden="true">#</a> 退出</h3><ul><li><code>:wq!</code> 强制保存退出</li><li><code>:wq</code> 保存退出</li><li><code>:x</code> 作用和:wq 一样</li><li><code>ZZ</code> 作用和:wq一样，(注意Z是大写的，并且不是在命令模式)</li><li><code>:q</code> 退出</li><li><code>:q!</code> 强制退出</li></ul><h3 id="移动" tabindex="-1"><a class="header-anchor" href="#移动" aria-hidden="true">#</a> 移动</h3><ul><li><code>h</code> 在当前行向左移动一个字符</li><li><code>j</code> 移动到下一行</li><li><code>k</code> 移动到上一行</li><li><code>l</code> 在当前行向右移动一个字符</li><li><code>Ctrl +f</code> 向前滚动一页</li><li><code>Ctrl +b</code> 向后滚动一页</li><li><code>:n</code> 将光标定位到第n行</li><li><code>:$</code> 将光标定位到最后一行</li><li><code>0</code> 将光标定位到本行的行首</li><li><code>$</code> 将光标定位到本行的行尾</li><li><code>G</code> 将光标定位到本文章的最后一行，与<code>:$</code>功能相同。</li></ul><h3 id="搜索" tabindex="-1"><a class="header-anchor" href="#搜索" aria-hidden="true">#</a> 搜索</h3><ul><li><code>/</code> 后面跟要查找的东西，在文件中向前搜索</li><li><code>?</code> 后面跟要查找的东西，在文件中向后搜索</li><li><code>n</code> 向前重复搜索</li><li><code>N</code> 向后重复搜索</li></ul><h3 id="插入" tabindex="-1"><a class="header-anchor" href="#插入" aria-hidden="true">#</a> 插入</h3><ul><li><code>i</code> 在当前位置的字符前面进入插入模式</li><li><code>I</code> 在当前行的开头进行插入</li><li><code>a</code> 在当前位置的字符后面进入插入模式</li><li><code>A</code> 在当前行的结尾进行插入</li><li><code>o</code> 在当前行下面打开一个新行进行插入</li><li><code>O</code> 在当前行上面打开一个新行进行插入</li></ul><h3 id="删除或剪切" tabindex="-1"><a class="header-anchor" href="#删除或剪切" aria-hidden="true">#</a> 删除或剪切</h3><ul><li><code>dd</code> 删除当前行</li><li><code>dw</code> 删除一个单词</li><li><code>x</code> 删除一个字符</li><li><code>nx</code> 删除n个字符</li><li><code>dG</code> 删除当前光标到文件末尾的所有内容。</li><li><code>d0</code> 删除当前光标到本行行首的所有内容</li><li><code>d$</code> 删除当前光标到本行行尾的所有内容</li><li><code>:1,100d</code> 删除1~100</li><li><code>:100d</code> 删除第100行</li><li><code>:1,100 mo $</code> 将1~100行的内容移动到最后一行。</li></ul><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>',33),s={href:"https://github.com/vim/vim",target:"_blank",rel:"noopener noreferrer"},p={href:"https://www.runoob.com/linux/linux-vim.html",target:"_blank",rel:"noopener noreferrer"},m={href:"https://zhuanlan.zhihu.com/p/61515833",target:"_blank",rel:"noopener noreferrer"};function f(x,_){const i=c("ExternalLinkIcon");return a(),r("div",null,[u,e("ul",null,[e("li",null,[e("a",s,[o("https://github.com/vim/vim"),d(i)])]),e("li",null,[e("a",p,[o("https://www.runoob.com/linux/linux-vim.html"),d(i)])]),e("li",null,[e("a",m,[o("https://zhuanlan.zhihu.com/p/61515833"),d(i)])])])])}const w=l(h,[["render",f],["__file","vim.html.vue"]]);export{w as default};
